1	'use client';
2	
3	import { useEffect, useRef, useState } from 'react';
4	import { Check, ChevronDown, Copy, Search } from 'lucide-react';
5	import { Button } from '@/components/ui/button';
6	import { cn } from '@/lib/utils';
7	import {
8	  CAPS,
9	  STAGE_REQUIREMENTS,
10	  meetsStageReq,
11	  missingReqs,
12	  type CapKey,
13	  type Stage,
14	} from '@/lib/stage-requirements';
15	import type { ReasoningEffort, AuxiliaryCapabilityFilter } from '@oracle/ai';
16	
17	export type { ReasoningEffort };
18	
19	// ---------------------------------------------------------------------------
20	// Types
21	// ---------------------------------------------------------------------------
22	
23	// Mirrors the ModelInfo shape from /api/admin/models — includes the canonical
24	// capability fields that match the model-pool DB columns and the shared
25	// stage-requirements module.
26	type Model = {
27	  id: string;
28	  name: string;
29	  provider: string;
30	  contextLength: number | null;
31	  promptPer1M: number | null;
32	  completionPer1M: number | null;
33	  vision: boolean;
34	  thinking: boolean;
35	  tools: boolean;
36	  structuredOutputs: boolean;
37	  promptCaching: boolean;
38	  outputCap: boolean;
39	  pdf: boolean;
40	};
41	
42	type Status = 'idle' | 'saving' | 'saved' | 'error';
43	
44	const EFFORT_OPTIONS: { value: ReasoningEffort; label: string }[] = [
45	  { value: 'off',    label: 'Off' },
46	  { value: 'low',    label: 'Low' },
47	  { value: 'medium', label: 'Medium' },
48	  { value: 'high',   label: 'High' },
49	];
50	
51	// ---------------------------------------------------------------------------
52	// Helpers
53	// ---------------------------------------------------------------------------
54	
55	function fmtPrice(n: number): string {
56	  if (n === 0) return '0';
57	  if (n < 0.001) return n.toFixed(5);
58	  if (n < 0.1) return n.toFixed(3);
59	  return n.toFixed(2);
60	}
61	
62	function fmtCtx(n: number): string {
63	  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(n % 1_000_000 === 0 ? 0 : 1)}M`;
64	  if (n >= 1_000) return `${Math.round(n / 1_000)}K`;
65	  return n.toLocaleString();
66	}
67	
68	function priceBadge(m: Model): string | null {
69	  if (m.promptPer1M == null) return null;
70	  if (m.promptPer1M === 0 && (m.completionPer1M ?? 0) === 0) return 'Free';
71	  return `$${fmtPrice(m.promptPer1M)} / $${fmtPrice(m.completionPer1M ?? 0)}`;
72	}
73	
74	/**
75	 * Derive the pipeline stage from a settings key like 'default_interview_route'.
76	 * Only used for the 3 pipeline-role pickers — auxiliary-model pickers (vision,
77	 * general-purpose) pass an explicit `auxiliary` prop instead.
78	 */
79	function stageFromKey(settingKey: string): Stage {
80	  if (settingKey.includes('interview')) return 'interview';
81	  if (settingKey.includes('extraction')) return 'extraction';
82	  if (settingKey.includes('synthesis')) return 'synthesis';
83	  return 'interview';
84	}
85	
86	// ---------------------------------------------------------------------------
87	// Sub-components
88	// ---------------------------------------------------------------------------
89	
90	/** Row of small capability icons for a model — used inside dropdown rows. */
91	function CapIcons({ model, size = 3 }: { model: Model; size?: number }) {
92	  const active = CAPS.filter((c) => (model as unknown as Record<CapKey, boolean>)[c.field]);
93	  if (active.length === 0) return null;
94	  return (
95	    <span className="flex items-center gap-0.5 shrink-0">
96	      {active.map((cap) => (
97	        <span key={cap.field} title={cap.long}>
98	          <cap.icon className={cn(`size-${size}`, cap.color)} />
99	        </span>
100	      ))}
101	    </span>
102	  );
103	}
104	
105	/** Icon legend — shown below the dropdown. */
106	function Legend() {
107	  return (
108	    <div className="rounded-md border bg-muted/20 px-3 py-2">
109	      <p className="text-xs font-medium text-muted-foreground mb-1.5">Icon legend</p>
110	      <div className="flex flex-wrap gap-x-4 gap-y-1">
111	        {CAPS.map((cap) => (
112	          <span key={cap.field} className="flex items-center gap-1 text-xs text-muted-foreground" title={cap.long}>
113	            <cap.icon className={cn('size-3', cap.color)} />
114	            {cap.short}
115	          </span>
116	        ))}
117	        <span className="flex items-center gap-1 text-xs text-muted-foreground" title="Cost per 1 million input / output tokens">
118	          <span className="font-mono text-[10px] text-muted-foreground">$/M</span>
119	          Price per 1M tokens (in&nbsp;/&nbsp;out)
120	        </span>
121	      </div>
122	    </div>
123	  );
124	}
125	
126	// ---------------------------------------------------------------------------
127	// Main component
128	// ---------------------------------------------------------------------------
129	
130	export function ModelPicker({
131	  currentModel,
132	  currentResolvedModel,
133	  currentEffort,
134	  settingKey,
135	  settingDescription,
136	  effortSettingKey,
137	  effortSettingDescription,
138	  clipboardBrief,
139	  auxiliary,
140	}: {
141	  currentModel: string | null;
142	  currentResolvedModel?: string | null;
143	  currentEffort: ReasoningEffort | null;
144	  settingKey: string;
145	  settingDescription: string;
146	  /** Settings key for the reasoning-effort dropdown. Optional —
147	   *  if omitted, the effort selector is hidden entirely (e.g. for general-purpose
148	   *  picker where there's no stage to associate effort with). */
149	  effortSettingKey?: string;
150	  effortSettingDescription?: string;
151	  /** When provided, a "Copy job brief" button appears next to the Model label
152	   *  and copies this detailed role description to the clipboard — useful for
153	   *  pasting into a model-evaluation prompt or vendor comparison. */
154	  clipboardBrief?: string;
155	  /** Set for auxiliary-model pickers (vision, general-purpose). When present,
156	   *  the model list is fetched by the aux id and filtered by its single
157	   *  required capability (if any) rather than by pipeline-stage requirements. */
158	  auxiliary?: { id: string; requiredCapability?: AuxiliaryCapabilityFilter };
159	}) {
160	  const [models, setModels] = useState<Model[]>([]);
161	  const [loading, setLoading] = useState(true);
162	  const [fetchError, setFetchError] = useState<string | null>(null);
163	  const [selected, setSelected] = useState<string>(
164	    currentModel ?? 'anthropic/claude-sonnet-4.6',
165	  );
166	  const [effort, setEffort] = useState<ReasoningEffort>(currentEffort ?? 'medium');
167	  const [status, setStatus] = useState<Status>('idle');
168	  const [saveError, setSaveError] = useState<string | null>(null);
169	  const [briefCopied, setBriefCopied] = useState(false);
170	
171	  async function copyBrief() {
172	    if (!clipboardBrief) return;
173	    try {
174	      await navigator.clipboard.writeText(clipboardBrief);
175	      setBriefCopied(true);
176	      setTimeout(() => setBriefCopied(false), 2500);
177	    } catch {
178	      // Clipboard API unavailable (insecure context / denied) — no-op.
179	    }
180	  }
181	
182	  // Dropdown open state + search filter.
183	  const [open, setOpen] = useState(false);
184	  const [query, setQuery] = useState('');
185	  const dropdownRef = useRef<HTMLDivElement>(null);
186	  const searchRef = useRef<HTMLInputElement>(null);
187	
188	  // Pipeline pickers filter by stage requirements; auxiliary pickers filter by
189	  // a single capability (or not at all). `stage` is null for auxiliary models.
190	  const stage: Stage | null = auxiliary ? null : stageFromKey(settingKey);
191	  const modelListParam = auxiliary ? auxiliary.id : (stage as Stage);
192	
193	  useEffect(() => {
194	    let cancelled = false;
195	    async function loadModels() {
196	      try {
197	        const res = await fetch(`/api/admin/models?stage=${modelListParam}`);
198	        if (!res.ok) {
199	          const body = await res.text();
200	          throw new Error(`${res.status}: ${body}`);
201	        }
202	        const data = (await res.json()) as { models: Model[] };
203	        if (!cancelled) {
204	          setModels(data.models);
205	          if (currentModel && data.models.some((m) => m.id === currentModel)) {
206	            setSelected(currentModel);
207	          }
208	        }
209	      } catch (err) {
210	        if (!cancelled) {
211	          setFetchError(err instanceof Error ? err.message : String(err));
212	        }
213	      } finally {
214	        if (!cancelled) setLoading(false);
215	      }
216	    }
217	    void loadModels();
218	    return () => { cancelled = true; };
219	  }, [currentModel, modelListParam]);
220	
221	  // Close on outside click.
222	  useEffect(() => {
223	    function handler(e: MouseEvent) {
224	      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
225	        setOpen(false);
226	        setQuery('');
227	      }
228	    }
229	    document.addEventListener('mousedown', handler);
230	    return () => document.removeEventListener('mousedown', handler);
231	  }, []);
232	
233	  // Focus search when dropdown opens.
234	  useEffect(() => {
235	    if (open) {
236	      setTimeout(() => searchRef.current?.focus(), 0);
237	    }
238	  }, [open]);
239	
240	  async function save() {
241	    setStatus('saving');
242	    setSaveError(null);
243	    try {
244	      // Save model selection.
245	      const res = await fetch('/api/admin/settings', {
246	        method: 'POST',
247	        headers: { 'Content-Type': 'application/json' },
248	        body: JSON.stringify({
249	          key: settingKey,
250	          value: selected,
251	          description: settingDescription,
252	        }),
253	      });
254	      if (!res.ok) throw new Error(`${res.status}: ${await res.text()}`);
255	
256	      // Save effort selection if applicable (and the selected model supports reasoning).
257	      if (effortSettingKey && selectedModel?.thinking) {
258	        const r2 = await fetch('/api/admin/settings', {
259	          method: 'POST',
260	          headers: { 'Content-Type': 'application/json' },
261	          body: JSON.stringify({
262	            key: effortSettingKey,
263	            value: effort,
264	            description: effortSettingDescription ?? `Reasoning effort for ${settingKey}.`,
265	          }),
266	        });
267	        if (!r2.ok) throw new Error(`${r2.status}: ${await r2.text()}`);
268	      }
269	
270	      setStatus('saved');
271	      setTimeout(() => setStatus('idle'), 3000);
272	    } catch (err) {
273	      setSaveError(err instanceof Error ? err.message : String(err));
274	      setStatus('error');
275	    }
276	  }
277	
278	  const selectedModel = models.find((m) => m.id === selected);
279	  const savedModel = currentModel ? models.find((m) => m.id === currentModel) : undefined;
280	
281	  // Pipeline pickers use the same stage predicates as the model-pool page.
282	  // Auxiliary pickers filter by a single capability flag (or show all models
283	  // when the aux model declares no required capability).
284	  const auxCap = auxiliary?.requiredCapability;
285	  const compatible = (
286	    auxiliary
287	      ? auxCap
288	        ? models.filter((m) => m[auxCap])
289	        : models
290	      : models.filter((m) => meetsStageReq(m, stage as Stage))
291	  ).sort((a, b) => (a.promptPer1M ?? Infinity) - (b.promptPer1M ?? Infinity));
292	
293	  const filtered = query.trim()
294	    ? compatible.filter(
295	        (m) =>
296	          m.id.toLowerCase().includes(query.toLowerCase()) ||
297	          m.name.toLowerCase().includes(query.toLowerCase()),
298	      )
299	    : compatible;
300	
301	  if (loading) {
302	    return <p className="text-sm text-muted-foreground">Loading available models…</p>;
303	  }
304	  if (fetchError) {
305	    return <p className="text-sm text-destructive">Failed to load models: {fetchError}</p>;
306	  }
307	
308	  // For stage pickers, find which requirements the *selected* model fails.
309	  // We use this to surface a small warning under the dropdown when an admin
310	  // somehow has a non-compliant model saved (e.g., from before stage reqs changed).
311	  const selectedMissing =
312	    selectedModel && !auxiliary ? missingReqs(selectedModel, stage as Stage) : [];
313	  const savedValueOutsidePicker = Boolean(currentModel && !savedModel);
314	
315	  const effortApplicable = effortSettingKey && selectedModel?.thinking === true;
316	
317	  return (
318	    <div className="space-y-4">
319	
320	      {/* ── Model + effort dropdowns (side by side when effort is applicable) ─ */}
321	      <div className="space-y-2">
322	        <div className="flex items-center justify-between gap-2">
323	          <label className="text-sm font-medium leading-none">Model</label>
324	          {clipboardBrief && (
325	            <button
326	              type="button"
327	              onClick={copyBrief}
328	              title="Copy a detailed brief of this model's job — what it's fed, what's expected, and which capabilities it needs — to your clipboard"
329	              className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors"
330	            >
331	              {briefCopied ? <Check className="size-3.5 text-green-600" /> : <Copy className="size-3.5" />}
332	              {briefCopied ? 'Copied' : 'Copy job brief'}
333	            </button>
334	          )}
335	        </div>
336	
337	        <div className="flex items-start gap-2">
338	          {/* Model dropdown */}
339	          <div className="relative flex-1 min-w-0" ref={dropdownRef}>
340	            <button
341	              type="button"
342	              onClick={() => { setOpen((v) => !v); }}
343	              disabled={status === 'saving'}
344	              className={cn(
345	                'w-full flex items-center justify-between gap-2 rounded-md border border-input bg-background px-3 py-2 text-sm',
346	                'ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2',
347	                'disabled:cursor-not-allowed disabled:opacity-50',
348	              )}
349	            >
350	              <span className="flex items-center gap-2 min-w-0">
351	                <span className="font-mono truncate">
352	                  {selected || 'Select a model…'}
353	                </span>
354	                {selectedModel && <CapIcons model={selectedModel} />}
355	              </span>
356	              <ChevronDown className={cn('size-4 shrink-0 text-muted-foreground transition-transform', open && 'rotate-180')} />
357	            </button>
358	
359	            {/* Floating list */}
360	            {open && (
361	              <div className="absolute z-50 mt-1 w-full rounded-md border bg-background shadow-lg">
362	                <div className="flex items-center gap-2 border-b px-3 py-2">
363	                  <Search className="size-3.5 shrink-0 text-muted-foreground" />
364	                  <input
365	                    ref={searchRef}
366	                    type="text"
367	                    placeholder="Search models…"
368	                    value={query}
369	                    onChange={(e) => setQuery(e.target.value)}
370	                    className="w-full bg-transparent text-sm outline-none placeholder:text-muted-foreground"
371	                  />
372	                </div>
373	                <ul className="max-h-72 overflow-y-auto py-1" role="listbox">
374	                  {filtered.length === 0 && (
375	                    <li className="px-3 py-4 text-center text-sm text-muted-foreground">
376	                      No models match &ldquo;{query}&rdquo;
377	                    </li>
378	                  )}
379	                  {filtered.map((m) => {
380	                    const badge = priceBadge(m);
381	                    const isSelected = m.id === selected;
382	                    return (
383	                      <li key={m.id} role="option" aria-selected={isSelected}>
384	                        <button
385	                          type="button"
386	                          onClick={() => {
387	                            setSelected(m.id);
388	                            setStatus('idle');
389	                            setOpen(false);
390	                            setQuery('');
391	                          }}
392	                          className={cn(
393	                            'w-full flex items-center justify-between gap-2 px-3 py-2 text-left text-sm hover:bg-muted',
394	                            isSelected && 'bg-muted/60',
395	                          )}
396	                        >
397	                          <span className="flex items-center gap-1.5 min-w-0">
398	                            <Check
399	                              className={cn(
400	                                'size-3.5 shrink-0',
401	                                isSelected ? 'text-foreground' : 'invisible',
402	                              )}
403	                            />
404	                            <span className="font-mono text-xs truncate">{m.id}</span>
405	                            <CapIcons model={m} size={3} />
406	                          </span>
407	                          {badge != null && (
408	                            <span
409	                              className={cn(
410	                                'shrink-0 rounded px-1.5 py-0.5 font-mono text-[10px]',
411	                                badge === 'Free'
412	                                  ? 'bg-emerald-50 text-emerald-700'
413	                                  : 'bg-muted text-muted-foreground',
414	                              )}
415	                            >
416	                              {badge}
417	                            </span>
418	                          )}
419	                        </button>
420	                      </li>
421	                    );
422	                  })}
423	                </ul>
424	
425	                <div className="border-t px-3 py-1.5 text-[10px] text-muted-foreground">
426	                  {filtered.length} of {compatible.length} compatible models
427	                </div>
428	              </div>
429	            )}
430	          </div>
431	
432	          {/* Effort dropdown (only when this is a stage picker AND selected model supports reasoning) */}
433	          {effortApplicable && (
434	            <div className="w-32 shrink-0">
435	              <select
436	                value={effort}
437	                onChange={(e) => { setEffort(e.target.value as ReasoningEffort); setStatus('idle'); }}
438	                title="Reasoning effort — translated per-provider (Anthropic budget_tokens, OpenAI reasoning_effort, Vertex thinkingBudget)"
439	                className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm
440	                           ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
441	              >
442	                {EFFORT_OPTIONS.map((opt) => (
443	                  <option key={opt.value} value={opt.value}>
444	                    Effort: {opt.label}
445	                  </option>
446	                ))}
447	              </select>
448	            </div>
449	          )}
450	        </div>
451	
452	        {/* Warning if the saved model fails the stage's current requirements */}
453	        {selectedMissing.length > 0 && (
454	          <p className="text-xs text-amber-600 dark:text-amber-400">
455	            ⚠ Selected model doesn&apos;t meet this stage&apos;s requirements:{' '}
456	            {selectedMissing.map((r) => r.label).join(', ')}
457	          </p>
458	        )}
459	        {savedValueOutsidePicker && (
460	          <div className="rounded border border-amber-200 bg-amber-50 px-3 py-2 text-xs text-amber-900">
461	            <p className="font-medium">Saved value is not in this dropdown&apos;s approved model pool.</p>
462	            <p className="mt-1">
463	              Saved setting:{' '}
464	              <code className="font-mono">{currentModel}</code>
465	              {currentResolvedModel && currentResolvedModel !== currentModel && (
466	                <>
467	                  {' '}
468	                  resolves at runtime to{' '}
469	                  <code className="font-mono">{currentResolvedModel}</code>.
470	                </>
471	              )}
472	            </p>
473	            <p className="mt-1">
474	              Choose a model from the dropdown and save to bring production back in
475	              sync with the approved pool.
476	            </p>
477	          </div>
478	        )}
479	      </div>
480	
481	      {/* ── Selected model detail card ────────────────────────────────────── */}
482	      {selectedModel && (
483	        <div className="rounded-md border bg-muted/30 px-4 py-3 text-xs space-y-1.5">
484	          <p className="font-medium text-sm text-foreground">{selectedModel.name}</p>
485	
486	          <div className="flex flex-wrap gap-x-4 gap-y-1 text-muted-foreground">
487	            {selectedModel.contextLength != null && (
488	              <span>Context: {fmtCtx(selectedModel.contextLength)} tokens</span>
489	            )}
490	            {selectedModel.promptPer1M != null && (
491	              <span>
492	                {selectedModel.promptPer1M === 0 && (selectedModel.completionPer1M ?? 0) === 0
493	                  ? 'Free'
494	                  : `$${fmtPrice(selectedModel.promptPer1M)} in / $${fmtPrice(selectedModel.completionPer1M ?? 0)} out per 1M tokens`
495	                }
496	              </span>
497	            )}
498	          </div>
499	
500	          {/* Active capabilities */}
501	          {CAPS.some((c) => (selectedModel as unknown as Record<CapKey, boolean>)[c.field]) && (
502	            <div className="flex flex-wrap gap-2 pt-0.5">
503	              {CAPS.filter((c) => (selectedModel as unknown as Record<CapKey, boolean>)[c.field]).map((cap) => (
504	                <span
505	                  key={cap.field}
506	                  title={cap.long}
507	                  className="flex items-center gap-1 text-xs text-muted-foreground"
508	                >
509	                  <cap.icon className={cn('size-3', cap.color)} />
510	                  {cap.short}
511	                </span>
512	              ))}
513	            </div>
514	          )}
515	        </div>
516	      )}
517	
518	      {/* ── Save button ───────────────────────────────────────────────────── */}
519	      <div className="flex items-center gap-3">
520	        <Button onClick={save} disabled={status === 'saving'} size="sm">
521	          {status === 'saving' ? 'Saving…' : effortApplicable ? 'Save model + effort' : 'Save model'}
522	        </Button>
523	        {status === 'saved' && (
524	          <span className="text-sm text-green-600">Saved.</span>
525	        )}
526	        {status === 'error' && saveError && (
527	          <span className="text-sm text-destructive">{saveError}</span>
528	        )}
529	      </div>
530	
531	      {currentModel && currentModel !== selected && status === 'idle' && (
532	        <p className="text-xs text-muted-foreground">
533	          Active model: <code className="font-mono">{currentModel}</code>
534	        </p>
535	      )}
536	
537	      {/* ── Icon legend ───────────────────────────────────────────────────── */}
538	      <Legend />
539	    </div>
540	  );
541	}
542	
543	// Re-export the per-stage requirements + helpers so server components rendering
544	// the stage card headers can show the same icon set the picker filters by.
545	export { STAGE_REQUIREMENTS } from '@/lib/stage-requirements';
546

