function providerModelId(provider: string, modelId: string): string {
  const prefix =
    provider === 'vertex'
      ? 'google'
      : provider === 'anthropic' ||
          provider === 'openai' ||
          provider === 'deepseek' ||
          provider === 'qwen'
        ? provider
        : provider;
  return `${prefix}/${modelId}`;
}

