    aria-label="Select this claim to translate for the China team"
  />
) : row.status === 'pending_review' ? (
  <input
    type="checkbox"
    name="claimId"
    value={row.id}
    form="bulk-evaluate"
    aria-label="Select this pending claim to ask someone to evaluate"
  />
) : (
  <span className="text-muted-foreground">—</span>
)}

