1	'use server';
2	
3	import { revalidatePath } from 'next/cache';
4	import { eq, inArray, sql } from 'drizzle-orm';
5	import { z } from 'zod';
6	import { employees, employeeDepartments, departments } from '@oracle/db';
7	import { getDirectDb } from '@oracle/db/client';
8	import { DEPARTMENTS, type Department } from '@oracle/shared';
9	import { requireAdmin } from '@/lib/auth-guard';
10	import { getServiceRoleSupabase } from '@/lib/supabase/server';
11	
12	const departmentIdEnum = z.enum(
13	  DEPARTMENTS as unknown as [Department, ...Department[]],
14	);
15	
16	const AddEmployeeSchema = z.object({
17	  name: z.string().min(1).max(255),
18	  email: z.string().email().max(320),
19	  role: z.string().min(1).max(255),
20	  // One or more department enum IDs, from a checkbox set.
21	  departmentIds: z.array(departmentIdEnum).min(1, 'At least one department is required.'),
22	  isAdmin: z.boolean(),
23	});
24	
25	export type AddEmployeeState = {
26	  ok: boolean;
27	  error?: string;
28	};
29	
30	export async function addEmployee(
31	  _prev: AddEmployeeState,
32	  formData: FormData,
33	): Promise<AddEmployeeState> {
34	  await requireAdmin();
35	  const db = getDirectDb();
36	
37	  const parsed = AddEmployeeSchema.safeParse({
38	    name: formData.get('name'),
39	    email: formData.get('email'),
40	    role: formData.get('role'),
41	    departmentIds: formData.getAll('departmentIds'),
42	    isAdmin: formData.get('isAdmin') === 'true',
43	  });
44	  if (!parsed.success) {
45	    return { ok: false, error: parsed.error.issues.map((i) => i.message).join('; ') };
46	  }
47	
48	  const { name, email, role, departmentIds, isAdmin } = parsed.data;
49	
50	  try {
51	    // Fetch display labels so the legacy text[] column carries human-readable
52	    // values (retrieval-plan.ts uses them as soft RRF hints — see the
53	    // comments on the employees.departments column in schema.ts).
54	    const labelRows = await db
55	      .select({ id: departments.id, label: departments.displayLabel })
56	      .from(departments)
57	      .where(inArray(departments.id, departmentIds));
58	    const labelById = new Map(labelRows.map((r) => [r.id, r.label]));
59	    const orderedLabels = departmentIds.map((id) => labelById.get(id) ?? id);
60	
61	    await db.transaction(async (tx) => {
62	      const [inserted] = await tx
63	        .insert(employees)
64	        .values({
65	          name,
66	          email,
67	          role,
68	          department: orderedLabels[0],
69	          departments: orderedLabels,
70	          isAdmin,
71	        })
72	        .onConflictDoNothing({ target: employees.email })
73	        .returning({ id: employees.id });
74	
75	      if (inserted) {
76	        await tx.insert(employeeDepartments).values(
77	          departmentIds.map((departmentId) => ({
78	            employeeId: inserted.id,
79	            departmentId,
80	          })),
81	        );
82	      }
83	    });
84	  } catch (err) {
85	    return { ok: false, error: err instanceof Error ? err.message : String(err) };
86	  }
87	
88	  revalidatePath('/admin/employees');
89	  revalidatePath('/admin/departments');
90	  return { ok: true };
91	}
92	
93	// ---------------------------------------------------------------------------
94	// Edit an existing employee's department membership.
95	// Overwrites the legacy employees.departments text[] AND the
96	// employee_departments join table in a single transaction.
97	// ---------------------------------------------------------------------------
98	
99	const UpdateEmployeeDepartmentsSchema = z.object({
100	  employeeId: z.string().uuid(),
101	  departmentIds: z.array(departmentIdEnum),
102	});
103	
104	export type UpdateEmployeeDepartmentsState = {
105	  ok: boolean;
106	  error?: string;
107	};
108	
109	export async function updateEmployeeDepartments(
110	  _prev: UpdateEmployeeDepartmentsState,
111	  formData: FormData,
112	): Promise<UpdateEmployeeDepartmentsState> {
113	  await requireAdmin();
114	  const db = getDirectDb();
115	
116	  const parsed = UpdateEmployeeDepartmentsSchema.safeParse({
117	    employeeId: formData.get('employeeId'),
118	    departmentIds: formData.getAll('departmentIds'),
119	  });
120	  if (!parsed.success) {
121	    return { ok: false, error: parsed.error.issues.map((i) => i.message).join('; ') };
122	  }
123	
124	  const { employeeId, departmentIds } = parsed.data;
125	
126	  try {
127	    const labelRows = departmentIds.length > 0
128	      ? await db
129	          .select({ id: departments.id, label: departments.displayLabel })
130	          .from(departments)
131	          .where(inArray(departments.id, departmentIds))
132	      : [];
133	    const labelById = new Map(labelRows.map((r) => [r.id, r.label]));
134	    const orderedLabels = departmentIds.map((id) => labelById.get(id) ?? id);
135	
136	    await db.transaction(async (tx) => {
137	      await tx.delete(employeeDepartments).where(eq(employeeDepartments.employeeId, employeeId));
138	      if (departmentIds.length > 0) {
139	        await tx.insert(employeeDepartments).values(
140	          departmentIds.map((departmentId) => ({
141	            employeeId,
142	            departmentId,
143	          })),
144	        );
145	      }
146	      await tx
147	        .update(employees)
148	        .set({
149	          department: orderedLabels[0] ?? null,
150	          departments: orderedLabels,
151	        })
152	        .where(eq(employees.id, employeeId));
153	    });
154	  } catch (err) {
155	    return { ok: false, error: err instanceof Error ? err.message : String(err) };
156	  }
157	
158	  revalidatePath('/admin/employees');
159	  revalidatePath('/admin/departments');
160	  return { ok: true };
161	}
162	
163	// ---------------------------------------------------------------------------
164	// Disable / re-enable employee access.
165	// Soft-disable via employees.disabled_at so historical messages, claims,
166	// evidence, assignments, and audit records keep their employee references.
167	// ---------------------------------------------------------------------------
168	
169	const UpdateEmployeeAccessSchema = z.object({
170	  employeeId: z.string().uuid(),
171	  action: z.enum(['disable', 'enable']),
172	});
173	
174	export type UpdateEmployeeAccessState = {
175	  ok: boolean;
176	  error?: string;
177	};
178	
179	export async function updateEmployeeAccess(
180	  _prev: UpdateEmployeeAccessState,
181	  formData: FormData,
182	): Promise<UpdateEmployeeAccessState> {
183	  const me = await requireAdmin();
184	  const db = getDirectDb();
185	
186	  const parsed = UpdateEmployeeAccessSchema.safeParse({
187	    employeeId: formData.get('employeeId'),
188	    action: formData.get('action'),
189	  });
190	  if (!parsed.success) {
191	    return { ok: false, error: parsed.error.issues.map((i) => i.message).join('; ') };
192	  }
193	
194	  const { employeeId, action } = parsed.data;
195	  if (action === 'disable' && employeeId === me.id) {
196	    return { ok: false, error: 'You cannot disable your own active admin account.' };
197	  }
198	
199	  try {
200	    const [target] = await db
201	      .select({
202	        id: employees.id,
203	        isAdmin: employees.isAdmin,
204	        disabledAt: employees.disabledAt,
205	      })
206	      .from(employees)
207	      .where(eq(employees.id, employeeId))
208	      .limit(1);
209	    if (!target) return { ok: false, error: 'Employee not found.' };
210	
211	    if (action === 'disable' && target.isAdmin && !target.disabledAt) {
212	      const adminCountResult = await db.execute(sql`
213	        SELECT count(*)::int AS active_admin_count
214	        FROM employees
215	        WHERE is_admin = true
216	          AND disabled_at IS NULL
217	          AND id <> ${employeeId}::uuid
218	      `);
219	      const activeAdminCount = Number(
220	        ([...adminCountResult][0] as { active_admin_count?: number } | undefined)
221	          ?.active_admin_count ?? 0,
222	      );
223	      if (activeAdminCount < 1) {
224	        return { ok: false, error: 'At least one active admin must remain.' };
225	      }
226	    }
227	
228	    await db
229	      .update(employees)
230	      .set({ disabledAt: action === 'disable' ? new Date() : null })
231	      .where(eq(employees.id, employeeId));
232	  } catch (err) {
233	    return { ok: false, error: err instanceof Error ? err.message : String(err) };
234	  }
235	
236	  revalidatePath('/admin/employees');
237	  return { ok: true };
238	}
239	
240	// ---------------------------------------------------------------------------
241	// Invite a Microsoft 365 user as a new Oracle employee.
242	//
243	// Distinct from addEmployee: allows zero departments (admin assigns later)
244	// and triggers a Supabase admin invite email so the recipient knows they've
245	// been added. When they next sign in (via Microsoft SSO or magic link), the
246	// existing identity linker matches by email and merges them in.
247	// ---------------------------------------------------------------------------
248	
249	const InviteFromM365Schema = z.object({
250	  email: z.string().email().max(320),
251	  name: z.string().min(1).max(255),
252	  // Optional at invite time. The admin will fix it via the inline editor
253	  // once the row exists, OR pre-pick a couple here if they already know.
254	  departmentIds: z.array(departmentIdEnum).optional().default([]),
255	  // Optional Graph-supplied job title.
256	  jobTitle: z.string().max(255).optional().default(''),
257	});
258	
259	export type InviteFromM365State = {
260	  ok: boolean;
261	  error?: string;
262	  /** Set to true when the DB insert succeeded but the email send failed. */
263	  emailFailed?: boolean;
264	};
265	
266	export async function inviteFromM365(
267	  _prev: InviteFromM365State,
268	  formData: FormData,
269	): Promise<InviteFromM365State> {
270	  await requireAdmin();
271	  const db = getDirectDb();
272	
273	  const parsed = InviteFromM365Schema.safeParse({
